1	import { _decorator, log, Vec3 } from "cc";
2	import GameView from "../GameView";
3	import { BaseState, eventManager, stateManager } from "db://astarte-framework/Managers";
4	import Game_Define from "../Game_Define";
5	import { FEATURE_WHEEL_EVENT } from "../FeatureWheel/FeatureWheelManager";
6	import { FeatureWheelSegmentType, FEATURE_WHEEL_SEGMENT_COUNT, SpinResult } from "../FeatureWheel/FeatureWheelTypes";
7	import { FEATURE_MARK_EVENT } from "../FeatureWheel/FeatureMarkEvent";
8	import { JP_EVENT, JP_Type } from "../JP/JP_Define";
9	import { SHAKE_EVENT } from "../ShakeManager";
10	import { REEL_MANAGER_EVENT } from "../ReelManager";
11	import { ar2es2Proto } from "@igs-arcade-division-rd2/uk_872_eyestrike2_proto";
12	
13	const { ccclass } = _decorator;
14	
15	/**
16	 * @ch Feature Wheel 轉輪演出 State（骨架 + 轉輪，不含落點後盤面效果）
17	 *
18	 * 位置：plate0 的 AWARD（對線獎）之後、ROUND_SHOW_END 之前（由 GameView.AfterShowWin 守衛導向）。
19	 * 對應規格 3.1 STEP3-5「檢查轉輪 → 觸發轉輪 → 第一次發動」；重轉（STEP6）仍為後續 plate。
20	 *
21	 * 職責邊界（scope = 骨架+轉輪演出）：
22	 *   IN  — SHOW_UI → 依 WheelFeatures 逐項 PLAY_SPIN(SlotIndex) 序列等待 → HIDE_UI → ROUND_SHOW_END
23	 *   OUT — 落點後的盤面演出（符號轉 CASH / 乘倍 badge / 升級 / FG 交棒）由後續 plate 停輪或後續階段處理
24	 *
25	 * 不在此 State 改動狀態機路由：FG（Type=0/4）的實際進場仍走既有 CheckState/LeaveRespin 的 IsGoingToFree。
26	 */
27	@ccclass( "FeatureWheelShowState" )
28	export class FeatureWheelShowState extends BaseState
29	{
30	    //#region 進場盤面效果參數（震動 + 盤面往下；需配合畫面實測微調）
31	    /**
32	     * @ch 盤面位移量（傳給 ZOOM_IN_REEL 的 targetLocalPos）。
33	     * ⚠️ ZoomInReel 公式：targetPos = 原座標 − targetLocalPos×scale → y 取「正」時盤面往「下」。
34	     *    動的是 GetZoomTarget()（GameView 整體），實際位移幅度需看畫面微調；BigWheel 若為其子節點會一起被移動。
35	     */
36	    private static readonly BOARD_ZOOM_POS = new Vec3( 0, 80, 0 );
37	    /**@ch 盤面縮放（1 = 只位移不放大；>1 會放大整個 GameView）*/
38	    private static readonly BOARD_ZOOM_SCALE = 1.25;
39	    /**@ch 盤面往下（ZoomIn）動畫時長（秒）*/
40	    private static readonly BOARD_ZOOM_IN_DURATION = 0.2;
41	    /**@ch 盤面還原（ZoomOut）動畫時長（秒）*/
42	    private static readonly BOARD_ZOOM_OUT_DURATION = 0.2;
43	    //#endregion
44	
45	    private m_gameView: GameView = null;
46	
47	    constructor( gameView: GameView )
48	    {
49	        super();
50	        this.m_gameView = gameView;
51	    }
52	
53	    public async OnEnter()
54	    {
55	        log( "OnEnter State : FEATURE_WHEEL_SHOW" );
56	
57	        // 只取「有效」轉輪項（Type≠None）。理論上進到此 State 必有 ≥1（AfterShowWin 已用 HasActiveWheel 守衛），
58	        // 此處再過濾一次防禦：把混在其中的 None 項剔除，避免無意義轉動。
59	        const features = ( this.m_gameView.RoundInfo?.WheelFeatures ?? [] )
60	            .filter( w => w != null && w.Type !== FeatureWheelSegmentType.None );
61	
62	        if ( features.length === 0 )
63	        {
64	            // 不應發生（守衛已擋）；fail-loud 但不炸狀態機，直接續流程
65	            console.warn( "[FeatureWheelShowState] 無有效 WheelFeatures，跳過轉輪演出" );
66	            stateManager.NextState( Game_Define.GameState.ROUND_SHOW_END );
67	            return;
68	        }
69	
70	        // 進場盤面效果：震動只在進場「震一下就停」（單次自停，避免轉動時持續晃很怪）；盤面往下(ZoomIn)持續整段、退場才還原。
71	        // 用 try/finally 保證 StopBoardEffect 一定執行（ZoomIn 記原始狀態，未配對盤面回不去）。
72	        this.StartBoardEffect();
73	        try
74	        {
75	            // 進場 Active（盤面下降+灰塵+光效）：一個 round 一次，落在第一次轉動前；await 播畢（Spine 缺失則立即返回不 hang）
76	            await this.PlayWheelEnter();
77	
78	            // WheelCount 迴圈：逐項「序列等待」——PlaySpin 有 m_isSpinning 重入守衛，
79	            // 未等前一次 callback 就發下一次會被靜默丟棄（FeatureWheelManager 行為，BC-2 硬約束）。
80	            for ( const wf of features )
81	            {
82	                const landIndex = wf.SlotIndex ?? 0;
83	
84	                // 防 hang：PlaySpin 對越界 landIndex 是 warn+return（不呼叫 callback）→ 若 await 會永久掛住。
85	                // 故在 dispatch 前先驗範圍，越界則 fail-loud 跳過該次（不 await）。
86	                if ( landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT )
87	                {
88	                    console.warn( `[FeatureWheelShowState] SlotIndex=${landIndex} 越界 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}，跳過該次轉動` );
89	                    continue;
90	                }
91	
92	                const result = await this.PlaySpinOnce( landIndex );
93	
94	                // fail-loud 一致性：落點 type 應與 server WheelFeatures.Type 相符
95	                // （前提 P：server SlotIndex 與客戶端 12 格序一致——待 server 對拍；不符僅 warn 不阻流程）
96	                if ( result != null && result.type !== wf.Type )
97	                {
98	                    console.warn( `[FeatureWheelShowState] 落點 type 不一致：landed=${result.type} vs server=${wf.Type}（SlotIndex=${landIndex}）` );
99	                }
100	
101	                // 飛個效果下來到盤面指定位置
102	                await this.PlayFlyEffect( wf );
103	
104	                // ②標記 seam：通知演出端在盤面標記此功能（標記/icon/乘倍/Grand報獎/FreeGame盤外 由同事 handler 渲染）。
105	                await this.PlayMarkEffect( wf );
106	
107	                // 落點顯示已由 BigWheel Collect 動畫（PlaySpin 內 await）負責，中間維持亮起至退場 Out；
108	                // 故不再需要結果展示牌的暫代 dwell 與 HIDE_RESULT。
109	            }
110	
111	            // ③轉換 seam：標記後、進 respin 前，套用符號轉換（一般符號→CASH）。fire-and-forget；演出由同事 handler 渲染。
112	            const transferResult = this.m_gameView.RoundInfo?.TransferResult ?? [];
113	            if ( transferResult.length > 0 )
114	            {
115	                await this.PlaySymbolTransferEffect( transferResult );
116	            }
117	
118	            // 退場 Out（盤面回歸+中間功能暗掉）：等全部轉動與效果（含 transfer）演完才播，一個 round 一次
119	            await this.PlayWheelExit();
120	        }
121	        finally
122	        {
123	            // 盤面效果收尾：停震動 + 還原 ZoomIn（await 還原完成，盤面回正後才續流程）。
124	            // 放 finally 確保即使上面拋例外也會停震動/還原盤面，不卡死畫面。
125	            await this.StopBoardEffect();
126	        }
127	
128	        eventManager.Dispatch( FEATURE_WHEEL_EVENT.RESUME_IDLE );
129	
