197	     * 方向跟隨 m_clockwise（順時針 = z 遞減，與 ComputeTargetAngle 一致）
198	     */
199	    update(dt: number) {
200	        if (!this.m_isIdle || this.m_isSpinning) {
201	            return;
202	        }
203	        if (this.m_idleSecondsPerRev <= 0) {
204	            return;
205	        }
206	        if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
207	            return;
208	        }
209	        const dir = this.m_clockwise ? -1 : 1;
210	        const deltaAngle = dir * (360 / this.m_idleSecondsPerRev) * dt;
211	        // 正規化防 BC-8 連續累積漂移（與 RotateToIndex 收尾一致），spin 起點讀 currentAngle 仍正確
212	        const next = NormalizeAngle(this.m_wheelNode.eulerAngles.z + deltaAngle);
213	        this.m_wheelNode.setRotationFromEuler(0, 0, next);
214	    }
