226	    private UnregisterEvent() {
227	        if (!this.m_isEventRegistered) {
228	            return;
229	        }
230	        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
231	        this.m_isEventRegistered = false;
232	    }
