237	    OnEvent(event: string, ...args: any[]) {
238	        switch (event) {
239	            case FEATURE_WHEEL_EVENT.INIT:
240	                if (args.length > 0 && typeof args[0] === 'object' && args[0] !== null) {
241	                    this.Init(args[0]);
242	                } else {
243	                    error('FeatureWheel INIT 參數無效');
244	                }
245	                break;
246	
247	            case FEATURE_WHEEL_EVENT.SET_WHEEL_DATA:
248	                if (args.length > 0 && Array.isArray(args[0])) {
249	                    this.SetWheelData(args[0]);
250	                } else {
251	                    error('FeatureWheel SET_WHEEL_DATA 參數無效');
252	                }
253	                break;
254	
255	            case FEATURE_WHEEL_EVENT.PLAY_SPIN:
256	                if (args.length > 0 && typeof args[0] === 'number') {
257	                    this.PlaySpin(args[0], typeof args[1] === 'function' ? args[1] : undefined);
258	                } else {
259	                    error('FeatureWheel PLAY_SPIN 參數無效');
260	                }
261	                break;
262	
263	            case FEATURE_WHEEL_EVENT.SHOW_UI:
264	                this.SetUIShow(true);
265	                break;
266	
267	            case FEATURE_WHEEL_EVENT.HIDE_UI:
268	                this.SetUIShow(false);
269	                break;
270	
271	            case FEATURE_WHEEL_EVENT.PLAY_ENTER:
272	                this.PlayEnter(typeof args[0] === 'function' ? args[0] : undefined);
273	                break;
274	
275	            case FEATURE_WHEEL_EVENT.PLAY_EXIT:
276	                this.PlayExit(typeof args[0] === 'function' ? args[0] : undefined);
277	                break;
278	
279	            case FEATURE_WHEEL_EVENT.RESUME_IDLE:
280	                this.ResumeIdle();
281	                break;
282	
283	            case FEATURE_WHEEL_EVENT.HIDE_RESULT:
284	                this.HideResult();
285	                break;
286	        }
